diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index cad17c511b6d..ae1a97ff4fea 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -732,37 +732,42 @@ static Value *tryFactorization(BinaryOperator &I, const SimplifyQuery &SQ,
   RetVal->takeName(&I);

   // Try to add no-overflow flags to the final value.
-  if (isa<OverflowingBinaryOperator>(RetVal)) {
-    bool HasNSW = false;
-    bool HasNUW = false;
-    if (isa<OverflowingBinaryOperator>(&I)) {
-      HasNSW = I.hasNoSignedWrap();
-      HasNUW = I.hasNoUnsignedWrap();
-    }
-    if (auto *LOBO = dyn_cast<OverflowingBinaryOperator>(LHS)) {
-      HasNSW &= LOBO->hasNoSignedWrap();
-      HasNUW &= LOBO->hasNoUnsignedWrap();
-    }
+  // Note: IRBuilder may constant fold the newly created operation, producing
+  // a ConstantExpr instead of an Instruction. Overflow flags only apply to
+  // Instructions, so guard the propagation accordingly.
+  if (auto *RetInst = dyn_cast<Instruction>(RetVal)) {
+    if (isa<OverflowingBinaryOperator>(RetInst)) {
+      bool HasNSW = false;
+      bool HasNUW = false;
+      if (isa<OverflowingBinaryOperator>(&I)) {
+        HasNSW = I.hasNoSignedWrap();
+        HasNUW = I.hasNoUnsignedWrap();
+      }
+      if (auto *LOBO = dyn_cast<OverflowingBinaryOperator>(LHS)) {
+        HasNSW &= LOBO->hasNoSignedWrap();
+        HasNUW &= LOBO->hasNoUnsignedWrap();
+      }

-    if (auto *ROBO = dyn_cast<OverflowingBinaryOperator>(RHS)) {
-      HasNSW &= ROBO->hasNoSignedWrap();
-      HasNUW &= ROBO->hasNoUnsignedWrap();
-    }
+      if (auto *ROBO = dyn_cast<OverflowingBinaryOperator>(RHS)) {
+        HasNSW &= ROBO->hasNoSignedWrap();
+        HasNUW &= ROBO->hasNoUnsignedWrap();
+      }

-    if (TopLevelOpcode == Instruction::Add && InnerOpcode == Instruction::Mul) {
-      // We can propagate 'nsw' if we know that
-      //  %Y = mul nsw i16 %X, C
-      //  %Z = add nsw i16 %Y, %X
-      // =>
-      //  %Z = mul nsw i16 %X, C+1
-      //
-      // iff C+1 isn't INT_MIN
-      const APInt *CInt;
-      if (match(V, m_APInt(CInt)) && !CInt->isMinSignedValue())
-        cast<Instruction>(RetVal)->setHasNoSignedWrap(HasNSW);
-
-      // nuw can be propagated with any constant or nuw value.
-      cast<Instruction>(RetVal)->setHasNoUnsignedWrap(HasNUW);
+      if (TopLevelOpcode == Instruction::Add && InnerOpcode == Instruction::Mul) {
+        // We can propagate 'nsw' if we know that
+        //  %Y = mul nsw i16 %X, C
+        //  %Z = add nsw i16 %Y, %X
+        // =>
+        //  %Z = mul nsw i16 %X, C+1
+        //
+        // iff C+1 isn't INT_MIN
+        const APInt *CInt;
+        if (match(V, m_APInt(CInt)) && !CInt->isMinSignedValue())
+          RetInst->setHasNoSignedWrap(HasNSW);
+
+        // nuw can be propagated with any constant or nuw value.
+        RetInst->setHasNoUnsignedWrap(HasNUW);
+      }
     }
   }
   return RetVal;

